-- ═══════════════════════════════════════════════════════════════════════════════
-- Mega Man X.lua — game module for the Archipelago BizHawk connector.
--                 Mega Man X (SNES)
--
-- STATUS: COMMUNITY world. location DETECTION + goal are REAL and SOURCE-DERIVED
-- from the official apworld worlds/mmx (Client.py game_watcher + Locations.py +
-- Levels.py, TheLX5/Archipelago @ branch `mmx`, world_version 1.6.2). The
-- 83-entry location table was GENERATED by JOINING Locations.all_locations
-- (name → AP id) with Levels.location_id_to_level_id (name → [stage, internal_id,
-- data_bit]) — not hand-copied — so every (AP id → internal_id/data_bit) pair is
-- exact. Mock-verified through MoonSharp against synthetic WRAM/CARTROM. Loads
-- crash-free on any ROM; self-disables on a non-AP cartridge.
--
-- SOURCE: https://github.com/TheLX5/Archipelago  (branch `mmx`, worlds/mmx)
--         game string "Mega Man X", patch_suffix ".apmmx", items_handling 0b111.
--
-- MEMORY MODEL (SNI → BizHawk)  — see Research_V2/SNES_BRIDGE_2026-06-12.md
-- ──────────────────────────────────────────────────────────────────────────
--   The mmx client is an SNIClient. Its SNI addresses translate to BizHawk SNES
--   memory domains:
--     SNI WRAM_START(0xF50000)+off → domain "WRAM",    offset off (= $7E0000+off)
--     SNI ROM_START(0x000000)+off  → domain "CARTROM", offset off (raw ROM file
--                                    offset; LoROM. Fallbacks "ROM"/"System Bus")
--   The client reads four contiguous RAM blocks; this module reads the same bytes:
--     • game_data       = snes_read(MMX_RAM = WRAM+0x1EE00, 0x140)   → WRAM
--         game_data[X]            → WRAM 0x1EE00 + X
--     • game_progress   = snes_read(MMX_UPGRADE_DATA = WRAM+0x01F10, 0xF0) → WRAM
--         game_progress[X]        → WRAM 0x01F10 + X
--     • game_state_data = snes_read(MMX_GAME_STATE = WRAM+0x000D1, 0x3)    → WRAM
--         game_state_data[0..2]   → WRAM 0x000D1 / 0x000D2 / 0x000D3
--     • game_settings   = snes_read(MMX_SETTINGS = ROM+0x167C20, 0x20)     → CARTROM
--         game_settings[X]        → CARTROM 0x167C20 + X
--   IDENTITY / VALIDATION (two gates, both mirrored from Client.py):
--     1) ROM header title at CARTROM 0x7FC0 begins with "MMX1" (validate_rom:
--        rom_name[:4] == b"MMX1"). This is baked by the AP basepatch.
--     2) The live AP-validation word game_data[0x13:0x15] (WRAM 0x1EE13/0x1EE14,
--        little-endian) == 0xDEAD (game_watcher's per-frame "ROM properly
--        validated" check). Only a patched-and-running ROM sets this.
--
-- HOW MMX CHECKS WORK (mirrors Client.py game_watcher; per-location internal_id)
--   Each location carries {internal_id, data_bit}:
--     0x000 Boss clear  : game_data[0x80 + data_bit] != 0          (INDEX, not mask)
--     0x001 Maverick    : game_data[0x60 + data_bit] != 0          (stage clear, INDEX)
--     0x002 Heart Tank  : game_data[0x05] & data_bit != 0          (MASK on one byte)
--     0x003 Upgrade     : game_data[0x06] & data_bit != 0          (MASK)
--     0x004 Sub Tank    : game_data[0x06] & data_bit != 0          (MASK; same byte as 003)
--     0x005 Hadouken    : game_data[0x07] != 0                     (data_bit unused)
--     0x007 Intro clear : game_state_data == {0x02,0x00,0x01} AND
--                          game_progress[0x8B] (WRAM 0x01F9B) == 0x04
--     0x020 Pickup      : gated on pickupsanity (game_settings[0x07], CARTROM
--                          0x167C27); game_data[0xC0 + data_bit] != 0  (INDEX)
--
-- WHAT THIS DOES
--   • poll(): the game_watcher location scan above → AP location ids, gated to the
--     slot's server location set and to the in-game state (game_state_data[0]==0x02,
--     i.e. a save is loaded and the player is in the world — game_watcher only
--     reports checks while game_state != 0 and treats state[0]==0x02 as "active").
--   • is_goal_complete(): Sigma defeated — the victory location
--     (Sigma's Fortress Stage 4 - Sigma Defeated) is internal_id 0x000, data_bit
--     0x1F → game_data[0x80 + 0x1F] = game_data[0x9F] (WRAM 0x1EE9F) != 0. The
--     apworld places the locked Victory item there; defeating Sigma is the goal.
--   • receive_item(): NO-OP (documented). items_handling = 0b111 (FULL remote) —
--     the mmx client owns ALL item delivery via an intricate, heavily-state-gated
--     set of WRAM writes (weapon/upgrade/sub-tank/heart-tank/enhancement/boss-
--     access arrays, a recv-index handshake at game_data[0x00:0x02], an SFX strobe,
--     a per-item queue that waits on menu/gameplay/pause/can-move/screen-brightness
--     states, an arsenal save/load round-trip through AP data-storage, plus
--     EnergyLink/DeathLink/SharedDamage). That path is the one piece that needs
--     in-emulator verification before it is wired, so it is left out rather than
--     shipped unverified (a wrong write would corrupt the save / desync recv-index).
--     Checks + goal above are fully functional regardless of this gap.
--
-- MODULE CONTRACT (called by bizhawk_ap_connector.lua)
--   M.init(ctx) / M.poll() -> {ids} / M.is_goal_complete() -> bool /
--   M.receive_item(item_id, meta)
-- ═══════════════════════════════════════════════════════════════════════════════

local M = {}
M.name = "Mega Man X"

local ADDRESSES_VERIFIED = true   -- table generated from worlds/mmx source

-- ── Memory domains ────────────────────────────────────────────────────────────
local WRAM    = "WRAM"
local CARTROM = "CARTROM"     -- SNES cartridge ROM in BizHawk; fallbacks below

-- ── Addresses / constants (worlds/mmx/Client.py module top) ───────────────────
-- Expressed as BizHawk-domain offsets (already net of WRAM_START / ROM_START).
local MMX_RAM_OFF       = 0x1EE00      -- WRAM: base of the 0x140-byte game_data block
local PROGRESS_OFF      = 0x01F10      -- WRAM: base of the 0xF0-byte game_progress block
local GAME_STATE_OFF    = 0x000D1      -- WRAM: game_state_data[0] (then +1, +2)
local SETTINGS_OFF      = 0x167C20     -- CARTROM: base of the 0x20-byte game_settings block
local ROMHASH_OFF       = 0x7FC0       -- CARTROM: ROM-header title; first 4 = "MMX1"

-- game_data[] sub-fields (offsets RELATIVE to MMX_RAM_OFF).
local GD_VALIDATION     = 0x13         -- u16 LE; == 0xDEAD when patched+running
local GD_HEART_TANKS    = 0x05         -- u8 mask: collected heart-tank flags
local GD_UPGRADES       = 0x06         -- u8 mask: collected upgrade/sub-tank flags
local GD_HADOUKEN       = 0x07         -- u8: != 0 once Hadouken collected
local GD_BOSSES_BASE    = 0x80         -- defeated_bosses[]; index by data_bit
local GD_CLEARED_BASE   = 0x60         -- cleared_levels[];  index by data_bit
local GD_PICKUPS_BASE   = 0xC0         -- collected_pickups[]; index by data_bit

-- game_progress[] sub-fields (offsets RELATIVE to PROGRESS_OFF).
local GP_INTRO_DONE     = 0x8B         -- completed_intro_level; == 0x04 on intro clear

-- game_settings[] sub-fields (offsets RELATIVE to SETTINGS_OFF, in CARTROM).
local GS_PICKUPSANITY   = 0x07         -- pickupsanity enabled?

-- Live validation word value.
local VALIDATION_OK     = 0xDEAD

-- Goal: Sigma defeated — boss clear index 0x1F (Sigma's Fortress 4 - Sigma).
local GOAL_BOSS_INDEX   = 0x1F

-- Check-type tags (Client.py game_watcher internal_id values).
local T_BOSS        = 0x000
local T_MAVERICK    = 0x001
local T_HEART_TANK  = 0x002
local T_UPGRADE     = 0x003
local T_SUB_TANK    = 0x004
local T_HADOUKEN    = 0x005
local T_INTRO       = 0x007
local T_PICKUP      = 0x020

-- ── Location table (GENERATED from worlds/mmx Locations.py ⋈ Levels.py) ────────
-- ap_id -> { internal_id, data_bit }. 83 entries. AP ids are absolute
-- location_name_to_id values (STARTING_ID 0xBE0800-based); detection is
-- self-contained (no per-slot base offset needed).
local LOC = {
  [12453888]={0x000,0x00},[12453889]={0x000,0x01},[12453890]={0x000,0x02},[12453891]={0x000,0x03},
  [12453892]={0x000,0x04},[12453893]={0x000,0x05},[12453894]={0x000,0x06},[12453895]={0x000,0x07},
  [12453896]={0x000,0x08},[12453897]={0x000,0x09},[12453898]={0x000,0x0A},[12453899]={0x000,0x0B},
  [12453900]={0x000,0x0C},[12453901]={0x000,0x0D},[12453902]={0x000,0x0E},[12453903]={0x000,0x0F},
  [12453904]={0x000,0x10},[12453905]={0x000,0x11},[12453906]={0x000,0x12},[12453907]={0x000,0x1E},
  [12453908]={0x000,0x13},[12453909]={0x000,0x1F},[12453910]={0x007,0x00},[12453911]={0x000,0x18},
  [12453912]={0x000,0x19},[12453913]={0x000,0x1A},[12453914]={0x000,0x1B},[12453915]={0x000,0x17},
  [12453916]={0x000,0x15},[12453917]={0x000,0x16},[12453918]={0x000,0x1C},[12453919]={0x000,0x1D},
  [12453936]={0x002,0x02},[12453937]={0x004,0x20},[12453938]={0x002,0x01},[12453939]={0x004,0x40},
  [12453940]={0x002,0x40},[12453941]={0x002,0x80},[12453942]={0x002,0x20},[12453943]={0x002,0x08},
  [12453944]={0x002,0x04},[12453945]={0x004,0x10},[12453946]={0x002,0x10},[12453947]={0x004,0x80},
  [12453952]={0x005,0x00},[12453953]={0x003,0x08},[12453954]={0x003,0x04},[12453955]={0x003,0x01},
  [12453956]={0x003,0x02},[12453968]={0x020,0x00},[12453969]={0x020,0x01},[12453970]={0x020,0x05},
